import { ChatOpenAI } from '@langchain/openai'
import { z, ZodSchema } from 'zod'
import { zodToJsonSchema } from 'zod-to-json-schema'

export class LLMClient {
  private llm: ChatOpenAI

  constructor(modelName = 'gpt-4o-mini', temperature = 0) {
    this.llm = new ChatOpenAI({ modelName, temperature })
  }

  async invokeStructured<T>(
    prompt: string,
    schema: ZodSchema<T>
  ): Promise<T> {
    const retryPrompt = `${prompt}\n\nIMPORTANT: Return only data that matches the required schema exactly. Do not add markdown, commentary, or extra wrapper text.`

    // Step 1: json_schema strict=true
    try {
      const llm1 = this.llm.withStructuredOutput(schema, {
        method: 'jsonSchema',
        strict: true,
      })
      return await llm1.invoke(retryPrompt) as T
    } catch (e) {
      console.warn('[LLM] Step 1 failed (strict=true):', e)
    }

    // Step 2: json_schema strict=false
    try {
      const llm2 = this.llm.withStructuredOutput(schema, {
        method: 'jsonSchema',
        strict: false,
      })
      return await llm2.invoke(retryPrompt) as T
    } catch (e) {
      console.warn('[LLM] Step 2 failed (strict=false):', e)
    }

    // Step 3: jsonMode
    try {
      const llm3 = this.llm.withStructuredOutput(schema, {
        method: 'jsonMode',
      })
      return await llm3.invoke(retryPrompt) as T
    } catch (e) {
      console.warn('[LLM] Step 3 failed (jsonMode):', e)
    }

    // Step 4: raw JSON parse from text
    const raw = await this.llm.invoke(retryPrompt)
    const text = typeof raw.content === 'string' ? raw.content : JSON.stringify(raw.content)
    const parsed = this.parseJsonFromText(text)
    return schema.parse(parsed)
  }

  private parseJsonFromText(text: string): unknown {
    // Extract JSON from ```json...``` or plain JSON
    const jsonMatch = text.match(/```json\s*([\s\S]*?)```/) || text.match(/\{[\s\S]*\}/)
    if (!jsonMatch) throw new Error('No JSON found in LLM response')
    return JSON.parse(jsonMatch[1] || jsonMatch[0])
  }
}
