import { StateGraph, Annotation } from '@langchain/langgraph'
import { SqliteSaver } from '@langchain/langgraph-checkpoint-sqlite'
import path from 'node:path'
import os from 'node:os'

// 상태 정의
const ChatStateAnnotation = Annotation.Root({
  messages: Annotation<any[]>({
    reducer: (x, y) => x.concat(y),
    default: () => [],
  }),
})

export async function buildChatGraph() {
  const graph = new StateGraph(ChatStateAnnotation)
    .addNode('agent', async (state) => {
      // 간단한 echo 노드 (Phase 1 검증용)
      return { messages: [{ role: 'assistant', content: 'Echo: ' + state.messages[state.messages.length - 1].content }] }
    })
    .addEdge('__start__', 'agent')
    .addEdge('agent', '__end__')

  return graph
}

export async function getChatApp(threadId: string) {
  const dbPath = path.join(os.homedir(), '.git-study', 'chat.db')
  const checkpointer = SqliteSaver.fromConnString(dbPath)
  const graph = await buildChatGraph()
  const app = graph.compile({ checkpointer })
  return { app, config: { configurable: { thread_id: threadId } } }
}
