import simpleGit, { SimpleGit, LogResult } from 'simple-git'
import path from 'node:path'

export interface CommitInfo {
  sha: string
  short_sha: string
  author: string
  date: string
  message: string
}

export async function getRepo(repoPath: string): Promise<SimpleGit> {
  const git = simpleGit(repoPath)
  // 유효성 검사
  const isRepo = await git.checkIsRepo()
  if (!isRepo) throw new Error(`Not a git repository: ${repoPath}`)
  return git
}

export async function getCommitListSnapshot(
  git: SimpleGit,
  maxCount = 100
): Promise<CommitInfo[]> {
  const log: LogResult = await git.log({ maxCount })
  return log.all.map((commit) => ({
    sha: commit.hash,
    short_sha: commit.hash.slice(0, 7),
    author: commit.author_name,
    date: commit.date,
    message: commit.message,
  }))
}

export async function buildCommitContext(
  git: SimpleGit,
  oldestSha: string,
  newestSha: string
): Promise<string> {
  const range = `${oldestSha}..${newestSha}`
  const log = await git.log({ from: oldestSha, to: newestSha })
  const diff = await git.diff([range])

  return `# Commit Range: ${range}\n\n## Commits\n${log.all.map(c => `- ${c.hash.slice(0, 7)} ${c.message}`).join('\n')}\n\n## Diff\n${diff}`
}
