import { SimpleGit } from 'simple-git'

export interface FileDiff {
  file_path: string
  status: 'A' | 'M' | 'D' | 'R'
  additions: number
  deletions: number
  diff: string
}

export async function getFileContentAtCommit(
  git: SimpleGit,
  sha: string,
  filePath: string
): Promise<string> {
  try {
    return await git.show([`${sha}:${filePath}`])
  } catch {
    return ''
  }
}

export async function getFileDiffs(
  git: SimpleGit,
  oldestSha: string,
  newestSha: string
): Promise<FileDiff[]> {
  const diffSummary = await git.diffSummary([`${oldestSha}..${newestSha}`])
  const files: FileDiff[] = []

  for (const file of diffSummary.files) {
    const diff = await git.diff([`${oldestSha}..${newestSha}`, '--', file.file])
    files.push({
      file_path: file.file,
      status: file.binary ? 'M' : 'M', // 간소화
      additions: file.insertions,
      deletions: file.deletions,
      diff,
    })
  }

  return files
}

export function detectCodeLanguage(filePath: string): string {
  const ext = filePath.split('.').pop() || ''
  const langMap: Record<string, string> = {
    ts: 'typescript',
    tsx: 'tsx',
    js: 'javascript',
    jsx: 'jsx',
    py: 'python',
    md: 'markdown',
    json: 'json',
  }
  return langMap[ext] || 'plaintext'
}
