export interface AnchorMatch {
  line_number: number
  confidence: number
}

export function findAnchorLine(
  codeLines: string[],
  anchorSnippet: string
): AnchorMatch | null {
  const anchorNormalized = anchorSnippet.trim().replace(/\s+/g, ' ')

  for (let i = 0; i < codeLines.length; i++) {
    const lineNormalized = codeLines[i].trim().replace(/\s+/g, ' ')
    if (lineNormalized.includes(anchorNormalized)) {
      return { line_number: i + 1, confidence: 1.0 }
    }
  }

  // Fuzzy match (간소화)
  for (let i = 0; i < codeLines.length; i++) {
    const line = codeLines[i].toLowerCase()
    const anchor = anchorNormalized.toLowerCase()
    if (line.includes(anchor.slice(0, Math.min(20, anchor.length)))) {
      return { line_number: i + 1, confidence: 0.7 }
    }
  }

  return null
}

export function parseFileContextBlocks(diffText: string): Map<string, string> {
  // diff에서 파일별 코드 블록 추출 (간소화)
  const blocks = new Map<string, string>()
  const fileRegex = /diff --git a\/(.+?) b\/(.+)/g
  let match
  while ((match = fileRegex.exec(diffText)) !== null) {
    blocks.set(match[2], diffText.slice(match.index, match.index + 500))
  }
  return blocks
}
