import { StateGraph, Annotation } from '@langchain/langgraph'
import { InlineQuizQuestionSchema } from '../types.js'
import { LLMClient } from '../llm/client.js'

const InlineQuizStateAnnotation = Annotation.Root({
  commit_context: Annotation<string>(),
  draft_questions: Annotation<any[]>({
    reducer: (x, y) => y,
    default: () => [],
  }),
  review_feedback: Annotation<string>({
    reducer: (x, y) => y,
    default: () => '',
  }),
  final_questions: Annotation<any[]>({
    reducer: (x, y) => y,
    default: () => [],
  }),
  iteration: Annotation<number>({
    reducer: (x, y) => y,
    default: () => 0,
  }),
})

export function buildInlineQuizGraph(llmClient: LLMClient) {
  const graph = new StateGraph(InlineQuizStateAnnotation)

  graph.addNode('draft', async (state) => {
    // 프롬프트 생성 (간소화)
    const prompt = `Generate inline quiz questions for:\n${state.commit_context}`
    const questions = await llmClient.invokeStructured(
      prompt,
      InlineQuizQuestionSchema.array()
    )
    return { draft_questions: questions, iteration: state.iteration + 1 }
  })

  graph.addNode('review', async (state) => {
    // 리뷰 로직 (간소화)
    const feedback = state.draft_questions.length > 0 ? 'APPROVED' : 'REJECTED'
    return { review_feedback: feedback }
  })

  graph.addNode('finalize', async (state) => {
    return { final_questions: state.draft_questions }
  })

  graph.addEdge('__start__', 'draft')
  graph.addEdge('draft', 'review')
  graph.addConditionalEdges('review', (state) => {
    return state.review_feedback === 'APPROVED' ? 'finalize' : 'draft'
  })
  graph.addEdge('finalize', '__end__')

  return graph
}
