import { StateGraph, Annotation } from '@langchain/langgraph'
import { InlineQuizGradeSchema } from '../types.js'
import { LLMClient } from '../llm/client.js'

const InlineGradeStateAnnotation = Annotation.Root({
  questions: Annotation<any[]>(),
  answers: Annotation<Record<string, string>>(),
  draft_grades: Annotation<any[]>({
    reducer: (x, y) => y,
    default: () => [],
  }),
  final_grades: Annotation<any[]>({
    reducer: (x, y) => y,
    default: () => [],
  }),
})

export function buildInlineGradeGraph(llmClient: LLMClient) {
  const graph = new StateGraph(InlineGradeStateAnnotation)

  graph.addNode('grade', async (state) => {
    const grades = await Promise.all(
      state.questions.map(async (q: any) => {
        const answer = state.answers[q.question_id] || ''
        const prompt = `Grade this answer:\nQuestion: ${q.question_text}\nAnswer: ${answer}`
        return await llmClient.invokeStructured(prompt, InlineQuizGradeSchema)
      })
    )
    return { draft_grades: grades }
  })

  graph.addNode('finalize', async (state) => {
    return { final_grades: state.draft_grades }
  })

  graph.addEdge('__start__', 'grade')
  graph.addEdge('grade', 'finalize')
  graph.addEdge('finalize', '__end__')

  return graph
}
