import { buildInlineQuizGraph } from '../graphs/inline_quiz_graph.js'
import { LLMClient } from '../llm/client.js'

export async function* streamInlineQuizProgress(
  commitContext: string
): AsyncGenerator<{ type: string; content?: any }> {
  const llmClient = new LLMClient()
  const graph = buildInlineQuizGraph(llmClient)
  const app = graph.compile()

  yield { type: 'start' }

  const stream = await app.stream({
    commit_context: commitContext,
  })

  for await (const event of stream) {
    if (event.draft) {
      yield { type: 'draft', content: event.draft.draft_questions }
    }
    if (event.finalize) {
      yield { type: 'done', content: event.finalize.final_questions }
    }
  }
}
