  return (
    <Box flexDirection="column" borderStyle="single" paddingX={1}>
      <Box>
        <Text color="green">&gt; </Text>
        <TextInput value={input} onChange={setInput} />
      </Box>
      {suggestions.length > 0 && (
        <Box marginTop={1}>
          <Text dimColor>Suggestions: {suggestions.join(', ')}</Text>
        </Box>
      )}
    </Box>
  )
