import React, { useState } from 'react'
import { render, Box } from 'ink'
import { AppStatusBar } from './components/AppStatusBar.js'
import { HistoryView } from './components/HistoryView.js'
import { CommandBar } from './components/CommandBar.js'
import { InlineCodeView } from './components/InlineCodeView.js'
import { AppMode } from '../types.js'

function App() {
  const [mode, setMode] = useState<AppMode>('idle')
  const [messages, setMessages] = useState<any[]>([])
  const [files, setFiles] = useState<string[]>(['example.ts'])
  const [selectedFile, setSelectedFile] = useState('example.ts')
  const [code, setCode] = useState('console.log("Hello")')
  const [questions, setQuestions] = useState<any[]>([])

  const handleCommand = async (cmd: string) => {
    if (cmd.startsWith('/quiz')) {
      setMode('quiz_loading')
      // streamInlineQuizProgress() 호출 (Phase 5에서 통합)
      setMode('quiz_answering')
    } else if (cmd.startsWith('/grade')) {
      setMode('grading')
      // streamInlineGradeProgress() 호출
      setMode('reviewing')
    } else {
      setMode('chatting')
      setMessages([...messages, { role: 'user', content: cmd }])
    }
  }

  return (
    <Box flexDirection="column" height="100%">
      <AppStatusBar repoName="example-repo" commitRange="abc123..def456" mode={mode} />
      <HistoryView messages={messages} />
      <InlineCodeView
        files={files}
        selectedFile={selectedFile}
        code={code}
        language="typescript"
        questions={questions}
      />
      <CommandBar onSubmit={handleCommand} />
    </Box>
  )
}

render(<App />)
